UPDATE content_schedule
SET status = 3,
    is_canceled = 1,
    last_error = #{reason}
WHERE task_id = #{taskId}
  AND status = 0
  AND user_id = #{userId}

UPDATE content_schedule
SET schedule_time = #{scheduleTime},
    content_data = #{contentData},
    idempotent_token = #{idempotentToken},
    last_error = #{reason}
WHERE task_id = #{taskId}
  AND status = 0
  AND (is_canceled IS NULL OR is_canceled = 0)
  AND user_id = #{userId}
